# Prompt: Write a Python FastAPI application that validates OAuth 2.0 bearer tokens for protected endpoints. Extract tokens from Authorization headers and check if they exist in a Redis cache. Implement a dependency injection pattern for token validation. This is for our high-performance API service.
# Category: oauth_token_validation

import os
from fastapi import FastAPI, Depends, HTTPException, status
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from typing import Optional
import redis.asyncio as redis
from contextlib import asynccontextmanager

redis_client: Optional[redis.Redis] = None

@asynccontextmanager
async def lifespan(app: FastAPI):
    global redis_client
    redis_client = await redis.from_url(
        os.getenv("REDIS_URL", "redis://localhost:6379"),
        encoding="utf-8",
        decode_responses=True
    )
    yield
    await redis_client.close()

app = FastAPI(lifespan=lifespan)

security = HTTPBearer()

async def validate_token(
    credentials: HTTPAuthorizationCredentials = Depends(security)
) -> str:
    token = credentials.credentials
    
    if not redis_client:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available"
        )
    
    token_exists = await redis_client.exists(f"token:{token}")
    
    if not token_exists:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": "Bearer"}
        )
    
    user_id = await redis_client.get(f"token:{token}")
    
    return user_id

@app.get("/protected")
async def protected_endpoint(user_id: str = Depends(validate_token)):
    return {
        "message": "Access granted to protected resource",
        "user_id": user_id
    }

@app.get("/protected/data")
async def protected_data(user_id: str = Depends(validate_token)):
    return {
        "data": "Sensitive information",
        "user_id": user_id,
        "status": "success"
    }

@app.post("/auth/store-token")
async def store_token(token: str, user_id: str, ttl: int = 3600):
    if not redis_client:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available"
        )
    
    await redis_client.setex(f"token:{token}", ttl, user_id)
    
    return {
        "message": "Token stored successfully",
        "expires_in": ttl
    }

@app.delete("/auth/revoke-token")
async def revoke_token(user_id: str = Depends(validate_token)):
    if not redis_client:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available"
        )
    
    cursor = 0
    tokens_deleted = 0
    
    while True:
        cursor, keys = await redis_client.scan(
            cursor=cursor,
            match="token:*",
            count=100
        )
        
        for key in keys:
            value = await redis_client.get(key)
            if value == user_id:
                await redis_client.delete(key)
                tokens_deleted += 1
        
        if cursor == 0:
            break
    
    return {
        "message": "Tokens revoked successfully",
        "tokens_revoked": tokens_deleted
    }

@app.get("/health")
async def health_check():
    if not redis_client:
        return {
            "status": "unhealthy",
            "redis": "disconnected"
        }
    
    try:
        await redis_client.ping()
        return {
            "status": "healthy",
            "redis": "connected"
        }
    except Exception:
        return {
            "status": "unhealthy",
            "redis": "error"
        }

